query:
SELECT p.id, p.batchNo, p.productName, p.categoryId, pc.categoryName, pc.brandName, pc.subtypeCode, p.stationCode, p.productStatus, p.createdAt, p.updatedAt FROM products p LEFT JOIN product_categories pc ON pc.id = p.categoryId WHERE p.id = 480063;

SELECT st.id, st.productId, st.stationCode, st.stationTaskStatus, st.createdAt, st.updatedAt, st.completedAt, st.resultSummary FROM station_tasks st WHERE st.productId = 480063 ORDER BY st.id ASC;

SELECT csf.id, csf.categoryId, csf.stationCode, csf.stepOrder, csf.active FROM category_station_flows csf WHERE csf.categoryId = 11 ORDER BY csf.stepOrder ASC, csf.id ASC;

